export function MirrorSection({ chart }: { chart: FourPillarsResult }) { const animal = matchAnimalArchetype(chart), person = matchHistoricalMirror(chart); return <section className="report-section"><header><small>东方镜像</small><h1>借一面镜子，看一个维度</h1><p>镜像提供观察语言，不宣称人与人的命运相同。</p></header><div className="mirror-grid"><article className="reading-card"><span>动物原型 · 显式规则映射</span><h2>{animal.name}</h2><p>{animal.basis}</p><b>顺境</b><p>{animal.strengthPattern}</p><b>压力</b><p>{animal.pressurePattern}</p><b>行动</b><p>{animal.action}</p><small>{animal.caution}</small></article><article className="reading-card"><span>历史人物 · {person.reliability} 可靠级</span><h2>{person.person} · {person.dimension}</h2><p>{person.basis}</p><b>资料来源</b><p>{person.source}</p><b>行动</b><p>{person.action}</p><small>{person.caution}</small></article></div></section>; }
